              >
                <div className={"flex-1 " + (index % 2 === 0 ? "lg:text-right" : "lg:text-left")}>
                  <div
                    className={
                      "rounded-2xl border border-slate-200 bg-white p-6 transition-colors hover:border-violet-300 lg:max-w-lg lg:p-8 " +
                      (index % 2 === 0 ? "lg:ml-auto" : "lg:mr-auto")
